01_dense_la_solve.code:
// Since input A is immutable, we must make a working copy
let mut mat = A.to_vec();
// We augment the matrix with vector b essentially
let mut rhs = b.to_vec();

// Forward Elimination
for k in 0..N {
    // 1. Partial Pivoting: Find max in column k
    let mut max_row = k;
    let mut max_val = mat[k * N + k].abs();

    for i in (k + 1)..N {
        let val = mat[i * N + k].abs();
        if val > max_val {
            max_val = val;
            max_row = i;
        }
    }

    // Swap rows if needed
    if max_row != k {
        for j in k..N {
            mat.swap(k * N + j, max_row * N + j);
        }
        rhs.swap(k, max_row);
    }

    let pivot = mat[k * N + k];
    // Singular check (basic)
    if pivot.abs() < 1e-12 {
        continue; 
    }

    // Eliminate rows below
    for i in (k + 1)..N {
        let factor = mat[i * N + k] / pivot;
        for j in (k + 1)..N {
            mat[i * N + j] -= factor * mat[k * N + j];
        }
        rhs[i] -= factor * rhs[k];
    }
}

// Back Substitution
for i in (0..N).rev() {
    let mut sum = rhs[i];
    for j in (i + 1)..N {
        sum -= mat[i * N + j] * x[j];
    }
    x[i] = sum / mat[i * N + i];
}

