if n < 3 {
    return 0.0;
}

let mut min_area = f64::MAX;

for i in 0..n - 2 {
    let p1 = points[i];
    for j in (i + 1)..n - 1 {
        let p2 = points[j];
        for k in (j + 1)..n {
            let p3 = points[k];

            let val = p1.x * (p2.y - p3.y) +
                      p2.x * (p3.y - p1.y) +
                      p3.x * (p1.y - p2.y);
            let area = 0.5 * val.abs();

            if area < min_area {
                min_area = area;
            }
        }
    }
}
